// dashboard/services/iteration.service.ts
export class IterationService {
  /**
   * 回滚到指定迭代
   */
  async rollback(iterationId: number): Promise<void> {
    const iteration = await this.findById(iterationId);
    if (!iteration) {
      throw new Error('Iteration not found');
    }

    // 使用 git checkout 回滚
    const { execSync } = require('child_process');
    execSync(`git checkout ${iteration.commitHash}`, {
      cwd: this.projectPath
    });

    // 更新状态
    await this.update(iterationId, { status: 'rolled_back' });
  }

  /**
   * 对比两个迭代
   */
  async diff(iterationId1: number, iterationId2: number): Promise<any> {
    const iter1 = await this.findById(iterationId1);
    const iter2 = await this.findById(iterationId2);

    const { execSync } = require('child_process');
    const diff = execSync(
      `git diff ${iter1.commitHash} ${iter2.commitHash}`,
      { encoding: 'utf-8' }
    );

    return {
      iteration1: iter1,
      iteration2: iter2,
      diff: diff
    };
  }
}

// dashboard/services/agent.service.ts
export class AgentService {
  /**
   * 获取 Agent 性能统计
   */
  async getStats(agentName: string, timeRange?: string): Promise<any> {
    const stats = await this.db.all(`
      SELECT 
        COUNT(*) as totalExecutions,
        AVG(executionTime) as avgExecutionTime,
        MIN(executionTime) as minExecutionTime,
        MAX(executionTime) as maxExecutionTime,
        SUM(CASE WHEN success = 1 THEN 1 ELSE 0 END) as successCount
      FROM agent_executions
      WHERE agentName = ?
        AND (? IS NULL OR timestamp >= datetime('now', '-' || ? || ' days'))
    `, [agentName, timeRange || 7, timeRange || 7]);

    return {
      agentName,
      totalExecutions: stats[0].totalExecutions,
      avgExecutionTime: stats[0].avgExecutionTime,
      minExecutionTime: stats[0].minExecutionTime,
      maxExecutionTime: stats[0].maxExecutionTime,
      successRate: (stats[0].successCount / stats[0].totalExecutions * 100).toFixed(2) + '%'
    };
  }
}
```

