#### 建议4：实现错误处理与重试机制

**时间**: 2天

```typescript
// utils/retry.ts
export class RetryManager {
  /**
   * 指数退避重试
   */
  static async retryWithBackoff<T>(
    fn: () => Promise<T>,
    options: {
      maxRetries?: number;
      initialDelay?: number;
      maxDelay?: number;
      backoffMultiplier?: number;
    } = {}
  ): Promise<T> {
    const {
      maxRetries = 3,
      initialDelay = 1000,
      maxDelay = 10000,
      backoffMultiplier = 2
    } = options;

    let delay = initialDelay;
    let lastError: Error;

    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        return await fn();
      } catch (error) {
        lastError = error;

        if (attempt === maxRetries) {
          throw lastError;
        }

        console.log(`⚠️ Retry ${attempt + 1}/${maxRetries} after ${delay}ms`);
        await this.sleep(delay);
        delay = Math.min(delay * backoffMultiplier, maxDelay);
      }
    }

    throw lastError;
  }

  static sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

// 使用示例
const result = await RetryManager.retryWithBackoff(
  async () => {
    return await this.agents.frontend.executeAndCollect(prompt);
  },
  { maxRetries: 3, initialDelay: 2000 }
);
