// monitoring/metrics-collector.ts
export class MetricsCollector {
  private metrics = {
    agentExecutionTimes: new Map<string, number[]>(),
    apiCallCounts: new Map<string, number>(),
    tokenUsage: { total: 0, byAgent: new Map<string, number>() },
    systemMetrics: []
  };

  recordAgentExecution(agentName: string, executionTime: number): void {
    if (!this.metrics.agentExecutionTimes.has(agentName)) {
      this.metrics.agentExecutionTimes.set(agentName, []);
    }
    this.metrics.agentExecutionTimes.get(agentName)!.push(executionTime);
  }

  getAverageExecutionTime(agentName: string): number {
    const times = this.metrics.agentExecutionTimes.get(agentName) || [];
    if (times.length === 0) return 0;
    return times.reduce((a, b) => a + b, 0) / times.length;
  }

  generateReport(): MetricsReport {
    return {
      timestamp: new Date(),
      agentPerformance: Array.from(this.metrics.agentExecutionTimes.keys()).map(agent => ({
        agent,
        avgExecutionTime: this.getAverageExecutionTime(agent),
        totalExecutions: this.metrics.agentExecutionTimes.get(agent)!.length
      })),
      totalApiCalls: Array.from(this.metrics.apiCallCounts.values()).reduce((a, b) => a + b, 0),
      totalTokens: this.metrics.tokenUsage.total
    };
  }
}
